package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedWriter;
import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithPathAndCharset() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Path path = mock(Path.class);
        BufferedWriter writer = mock(BufferedWriter.class);
        CSVPrinter printer = mock(CSVPrinter.class);

        // Use reflection to mock Files.newBufferedWriter(path, charset)
        Method newBufferedWriterMethod = Files.class.getMethod("newBufferedWriter", Path.class, java.nio.charset.Charset.class);

        // Create a proxy to intercept calls to Files.newBufferedWriter
        // Since Mockito.mockStatic is not available, we use a wrapper method in CSVFormat for testing or reflection to replace method call

        // Instead, we spy CSVFormat and override print(Path, Charset) to call print(BufferedWriter) with mocked writer
        CSVFormat spyFormat = spy(csvFormat);

        // When print(writer) is called, return mocked printer
        doReturn(printer).when(spyFormat).print(writer);

        // Override Files.newBufferedWriter call by mocking the method using a custom method in spy
        CSVFormat spyFormatWithOverride = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                assertEquals(path, out);
                assertEquals(StandardCharsets.UTF_8, charset);
                return print(writer);
            }
        };

        CSVFormat spyFormatFinal = spy(spyFormatWithOverride);
        doReturn(printer).when(spyFormatFinal).print(writer);

        CSVPrinter result = spyFormatFinal.print(path, StandardCharsets.UTF_8);
        assertNotNull(result);
        assertEquals(printer, result);

        verify(spyFormatFinal).print(writer);
    }

    @Test
    void testPrintWithIOExceptionFromFilesNewBufferedWriter() throws IOException {
        Path path = mock(Path.class);

        // We override print(Path, Charset) to throw IOException to simulate Files.newBufferedWriter throwing IOException
        CSVFormat csvFormatWithException = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                throw new IOException("Test IOException");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> csvFormatWithException.print(path, StandardCharsets.UTF_8));
        assertEquals("Test IOException", thrown.getMessage());
    }
}
